// Bilet uchun 20 ta savolni qaytaradi.
export function getTicketQuestions(ticketNumber) {
  return TICKETS[ticketNumber] || [];
}

// Oddiy, tez va deterministik pseudo-random generator (aralashtirish uchun)
function seededRandom(seed) {
  let s = seed % 2147483647;
  if (s <= 0) s += 2147483646;
  return function next() {
    s = (s * 16807) % 2147483647;
    return (s - 1) / 2147483646;
  };
}

function shuffleWithSeed(array, rand) {
  const arr = [...array];
  for (let i = arr.length - 1; i > 0; i--) {
    const j = Math.floor(rand() * (i + 1));
    [arr[i], arr[j]] = [arr[j], arr[i]];
  }
  return arr;
}

// Barcha biletlardagi savollarni yagona ro'yxat sifatida qaytaradi.
// Ilgari bu mantiq getRandomExamQuestions ichida yashiringan edi; endi
// rasmiy imtihon moduli ham shundan foydalanadi (takrorlanmasligi uchun).
export function getAllQuestions() {
  return Object.values(TICKETS).flat();
}

// Imtihon rejimi uchun — har chaqirilganda TASODIFIY 20 ta savol (barcha 61 bilet bazasidan aralashtirilib)
export function getRandomExamQuestions() {
  const allQuestions = getAllQuestions();
  const rand = Math.random;
  return shuffleWithSeed(allQuestions, rand).slice(0, QUESTIONS_PER_TICKET);
}
